function App() {
  const [showBorder, setShowBorder] = useState(false);

  return (
    <div>
      {/* Counter is always at position 0 and always type Counter */}
      {/* Its state (count) is preserved regardless of showBorder */}
      <Counter style={{ border: showBorder ? '2px solid red' : 'none' }} />
      <button onClick={() => setShowBorder(b => !b)}>Toggle border</button>
    </div>
  );
}

function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
// Clicking Toggle border: Counter re-renders with new props, count stays the same.

function App({ fancy }) {
  return (
    <div>
      {/* Position 0 is sometimes Counter, sometimes FancyCounter */}
      {fancy ? <FancyCounter /> : <Counter />}
    </div>
  );
}
// When fancy flips: React sees a different type at position 0.
// Counter unmounts (cleanup runs), FancyCounter mounts (effects run).
// FancyCounter's count starts at 0, not at Counter's last value.

// This is true even if both components render identically —
// the type reference is what matters, not the output.

function App({ showFilter }) {
  const [text, setText] = useState('');

  return (
    <div>
      {showFilter && <FilterBar />}        {/* pos 0 when true, GONE when false */}
      <input value={text} onChange={e => setText(e.target.value)} />
      {/* Position of <input> is 1 when showFilter=true, 0 when false */}
    </div>
  );
}
// When showFilter changes from true to false:
// - FilterBar at pos 0 unmounts (its state lost)
// - input shifts from pos 1 to pos 0 — React sees a type change at pos 0!
// - input unmounts and remounts — text state is RESET

// Fix: use null to keep positions stable
function App({ showFilter }) {
  const [text, setText] = useState('');
  return (
    <div>
      {showFilter ? <FilterBar /> : null}  {/* pos 0 always, null or FilterBar */}
      <input value={text} onChange={e => setText(e.target.value)} />
      {/* input is always at pos 1 — never moves */}
    </div>
  );
}

// This renders the text "0" — not nothing
function CountBadge({ count }) {
  return <div>{count && <span>{count}</span>}</div>;
}
<CountBadge count={0} />  // renders <div>0</div> — the 0 is a text node

// Fix: use explicit null
function CountBadge({ count }) {
  return <div>{count ? <span>{count}</span> : null}</div>;
}
<CountBadge count={0} />  // renders <div></div>

function Parent({ label }) {
  // NEW function object on every Parent render
  function Child() {
    const [count, setCount] = useState(0);
    return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
  }

  return (
    <div>
      <Child />   {/* type = Child, but Child is a new reference every render */}
    </div>
  );
}
// Every time Parent re-renders (label changes, etc.):
// - React sees a NEW type at position 0
// - Unmounts the previous Child (count lost), mounts a new one (count=0)
// The counter appears to reset on every parent re-render.

// Fix: define at module scope
function Child() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

function Parent({ label }) {
  return <div><Child /></div>;
  // Now type is the stable module-level Child — state is preserved
}

function App({ swap }) {
  return (
    <div>
      {/* Both are Counter — same type at positions 0 and 1 */}
      {swap
        ? <><Counter id="b" /><Counter id="a" /></>
        : <><Counter id="a" /><Counter id="b" /></>
      }
    </div>
  );
}
// Increment the first counter (id="a", count=5).
// Toggle swap.
// Result: count=5 is now shown for id="b"!
// Reason: pos 0 still has Counter, pos 1 still has Counter —
// React updates props (id changes), but state (count) stays with the Fiber.

// Fix: give each Counter a unique key so React tracks identity, not position
function App({ swap }) {
  const [a, b] = swap ? ['b', 'a'] : ['a', 'b'];
  return (
    <div>
      <Counter key={a} id={a} />
      <Counter key={b} id={b} />
    </div>
  );
}
// Now key="a" always owns the count-for-a state, regardless of render order.

// Strategy 1: unmount — state resets on hide
function App({ showPanel }) {
  return <div>{showPanel && <ExpensivePanel />}</div>;
}

// Strategy 2: CSS display — state preserved while hidden
function App({ showPanel }) {
  return (
    <div>
      <ExpensivePanel style={{ display: showPanel ? 'block' : 'none' }} />
    </div>
  );
}

// Strategy 3: lift state up — keep state in parent, not in component
function App() {
  const [count, setCount] = useState(0);
  const [showPanel, setShowPanel] = useState(true);
  return (
    <div>
      {/* Panel unmounts but count lives in App — survives hide/show */}
      {showPanel && <StatelessPanel count={count} onCount={setCount} />}
    </div>
  );
}

// When the type or position changes:
// 1. Old component: useEffect cleanup runs (synchronous, before DOM removal)
// 2. Old component: useLayoutEffect cleanup runs
// 3. Old DOM subtree is removed
// 4. New component: new DOM subtree is inserted
// 5. New component: useLayoutEffect runs
// 6. New component: useEffect runs (after paint)

function App({ view }) {
  return view === 'a' ? <ViewA /> : <ViewB />;
}

function ViewA() {
  useEffect(() => {
    console.log('ViewA mounted');
    return () => console.log('ViewA unmounted');
  }, []);
  return <p>View A</p>;
}

// Switching from A to B:
// > ViewA unmounted
// > (DOM updated)
// > ViewB mounted

function Timer() {
  const timerRef = useRef(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    timerRef.current = setInterval(() => {
      setElapsed(s => s + 1);
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  return <p>{elapsed}s</p>;
}

// Adding key={someValue} to <Timer /> and changing it resets both
// elapsed (useState) and timerRef.current (useRef returns to null —
// the old timer was cleared by cleanup).

// In contrast, a parent re-render without a type or position change:
// - elapsed is preserved (same Fiber, same useState)
// - timerRef.current is preserved (same Fiber, same useRef)

// Problem: conditional sibling shifts form's position
function CheckoutFlow({ showPromoCode }) {
  return (
    <div>
      {showPromoCode && <PromoCodeInput />}  {/* shifts everything below */}
      <ShippingForm />                        {/* position changes! */}
    </div>
  );
}
// User fills in ShippingForm. Clicks "I have a promo code".
// PromoCodeInput appears at pos 0 — ShippingForm shifts from pos 0 to pos 1.
// React sees a different element at the old pos 0 and destroys ShippingForm.
// User's typed data is gone.

// Fix: use null to keep ShippingForm at a stable position
function CheckoutFlow({ showPromoCode }) {
  return (
    <div>
      {showPromoCode ? <PromoCodeInput /> : null}  {/* pos 0: stable slot */}
      <ShippingForm />                               {/* pos 1: always */}
    </div>
  );
}

// React Router: layout component wraps routes
function Layout() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  return (
    <div>
      <Sidebar open={sidebarOpen} onToggle={() => setSidebarOpen(o => !o)} />
      <main>
        <Outlet />  {/* Only this subtree remounts on route change */}
      </main>
    </div>
  );
}

// Page-level state resets on route change
function ProductPage() {
  const [tab, setTab] = useState('description');  // resets on route change
  return <TabPanel activeTab={tab} onTabChange={setTab} />;
}

const CartContext = React.createContext({ items: [] });

function CartProvider({ children }) {
  const [items, setItems] = useState([]);
  // If CartProvider unmounts and remounts, items resets to []
  return (
    <CartContext.Provider value={{ items, setItems }}>
      {children}
    </CartContext.Provider>
  );
}
// Place providers as high as possible in the tree — typically at the app root

import { lazy, Suspense } from 'react';
const HeavyDashboard = lazy(() => import('./HeavyDashboard'));

function App({ showDashboard }) {
  return (
    <div>
      {showDashboard && (
        <Suspense fallback={<p>Loading dashboard...</p>}>
          <HeavyDashboard />
        </Suspense>
      )}
    </div>
  );
}
// HeavyDashboard state is always fresh — it mounts after the import resolves,
// and remounts if showDashboard toggles (conditional mount pattern)

// In StrictMode (development only), React:
// 1. Renders the component tree once
// 2. Unmounts it (runs cleanup effects)
// 3. Remounts it (re-runs setup effects)
// This surfaces bugs where cleanup does not fully reverse setup.

function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    console.log('effect setup, count is:', count);
    return () => console.log('effect cleanup');
  }, []);

  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// In development with StrictMode, console shows:
// effect setup, count is: 0
// effect cleanup
// effect setup, count is: 0  <- second mount; state reset to initial value
// (In production: only the first two lines appear)
